myNumberInput = (label, value = 0) =&gt; {
  const input = Inputs.number({label, value})
  const box = html`&lt;div class="my-2"&gt;${input}&lt;/div&gt;`
  Object.defineProperty(box, "value", {
    get: () =&gt; input.value
  })
  box.addEventListener("input", () =&gt;
    box.dispatchEvent(new Event("input", {bubbles: true}))
  )
  return box
}

